102	bool MutableTransactionSignatureCreator::CreateSchnorrSig(const SigningProvider& provider, std::vector<unsigned char>& sig, const XOnlyPubKey& pubkey, const uint256* leaf_hash, const uint256* merkle_root, SigVersion sigversion) const
103	{
104	    CKey key;
105	    if (!provider.GetKeyByXOnly(pubkey, key)) return false;
106	
107	    std::optional<uint256> hash = ComputeSchnorrSignatureHash(leaf_hash, sigversion);
108	    if (!hash.has_value()) return false;
109	
110	    sig.resize(64);
111	    // Use uint256{} as aux_rnd for now.
112	    if (!key.SignSchnorr(*hash, sig, merkle_root, {})) return false;
113	    if (m_options.sighash_type) sig.push_back(m_options.sighash_type);
114	    return true;
115	}
