118	{
119	    assert(sigversion == SigVersion::TAPROOT || sigversion == SigVersion::TAPSCRIPT);
120	
121	    // Retrieve the private key
122	    CKey key;
123	    if (!provider.GetKey(part_pubkey.GetID(), key)) return {};
124	
125	    // Retrieve participant pubkeys
126	    auto it = sigdata.musig2_pubkeys.find(aggregate_pubkey);
127	    if (it == sigdata.musig2_pubkeys.end()) return {};
128	    const std::vector<CPubKey>& pubkeys = it->second;
129	    if (std::find(pubkeys.begin(), pubkeys.end(), part_pubkey) == pubkeys.end()) return {};
130	
131	    // Compute sighash
132	    std::optional<uint256> sighash = ComputeSchnorrSignatureHash(leaf_hash, sigversion);
133	    if (!sighash.has_value()) return {};
134	
135	    MuSig2SecNonce secnonce;
136	    std::vector<uint8_t> out = ::CreateMuSig2Nonce(secnonce, *sighash, key, aggregate_pubkey, pubkeys);
137	    if (out.empty()) return {};
138	
139	    // Store the secnonce in the SigningProvider
140	    provider.SetMuSig2SecNonce(MuSig2SessionID(script_pubkey, part_pubkey, *sighash, out), std::move(secnonce));
141	
142	    return out;
143	}
