376	static bool CreateTaprootScriptSig(const BaseSignatureCreator& creator, SignatureData& sigdata, const SigningProvider& provider, std::vector<unsigned char>& sig_out, const XOnlyPubKey& pubkey, const uint256& leaf_hash, SigVersion sigversion)
377	{
378	    KeyOriginInfo info;
379	    if (provider.GetKeyOriginByXOnly(pubkey, info)) {
380	        auto it = sigdata.taproot_misc_pubkeys.find(pubkey);
381	        if (it == sigdata.taproot_misc_pubkeys.end()) {
382	            sigdata.taproot_misc_pubkeys.emplace(pubkey, std::make_pair(std::set<uint256>({leaf_hash}), info));
383	        } else {
384	            it->second.first.insert(leaf_hash);
385	        }
386	    }
387	
388	    auto lookup_key = std::make_pair(pubkey, leaf_hash);
389	    auto it = sigdata.taproot_script_sigs.find(lookup_key);
390	    if (it != sigdata.taproot_script_sigs.end()) {
391	        sig_out = it->second;
392	        return true;
393	    }
394	
395	    if (creator.CreateSchnorrSig(provider, sig_out, pubkey, &leaf_hash, nullptr, sigversion)) {
396	        sigdata.taproot_script_sigs[lookup_key] = sig_out;
397	    } else if (!SignMuSig2(creator, sigdata, provider, sig_out, pubkey, /*merkle_root=*/nullptr, &leaf_hash, sigversion)) {
398	        return false;
399	    }
400	
401	    return sigdata.taproot_script_sigs.contains(lookup_key);
402	}
