728	static CScript PushAll(const std::vector<valtype>& values)
729	{
730	    CScript result;
731	    for (const valtype& v : values) {
732	        if (v.size() == 0) {
733	            result << OP_0;
734	        } else if (v.size() == 1 && v[0] >= 1 && v[0] <= 16) {
735	            result << CScript::EncodeOP_N(v[0]);
736	        } else if (v.size() == 1 && v[0] == 0x81) {
737	            result << OP_1NEGATE;
738	        } else {
739	            result << v;
740	        }
741	    }
742	    return result;
743	}
