840	std::optional<PartiallySignedTransaction> CombinePSBTs(const std::vector<PartiallySignedTransaction>& psbtxs)
841	{
842	    PartiallySignedTransaction out = psbtxs[0]; // Copy the first one
843	
844	    // Merge
845	    for (auto it = std::next(psbtxs.begin()); it != psbtxs.end(); ++it) {
846	        if (!out.Merge(*it)) {
847	            return std::nullopt;
848	        }
849	    }
850	    return out;
851	}
