1088	/** RAII object to check and reserve a wallet rescan */
1089	class WalletRescanReserver
1090	{
1091	private:
1092	    using Clock = std::chrono::steady_clock;
1093	    using NowFn = std::function<Clock::time_point()>;
1094	    CWallet& m_wallet;
1095	    bool m_could_reserve{false};
1096	    NowFn m_now;
1097	public:
1098	    explicit WalletRescanReserver(CWallet& w) : m_wallet(w) {}
1099	
1100	    bool reserve(bool with_passphrase = false)
1101	    {
1102	        assert(!m_could_reserve);
1103	        if (m_wallet.fScanningWallet.exchange(true)) {
1104	            return false;
1105	        }
1106	        // Discard any abort request left over from previous reservation, so
1107	        // that an abort requested while the reservation is held always applies
1108	        // to abort this rescan, even if it arrives before the scan loop starts.
1109	        m_wallet.fAbortRescan = false;
1110	        m_wallet.m_scanning_with_passphrase.exchange(with_passphrase);
1111	        m_wallet.m_scanning_start = SteadyClock::now();
1112	        m_wallet.m_scanning_progress = 0;
1113	        m_could_reserve = true;
1114	        return true;
1115	    }
1116	
1117	    bool isReserved() const
1118	    {
1119	        return (m_could_reserve && m_wallet.fScanningWallet);
1120	    }
1121	
1122	    Clock::time_point now() const { return m_now ? m_now() : Clock::now(); };
1123	
1124	    void setNow(NowFn now) { m_now = std::move(now); }
1125	
1126	    ~WalletRescanReserver()
1127	    {
1128	        if (m_could_reserve) {
1129	            m_wallet.fScanningWallet = false;
1130	            m_wallet.m_scanning_with_passphrase = false;
1131	        }
1132	    }
1133	};
