24	//! mined, or conflicts with a mined transaction. Return a feebumper::Result.
25	static feebumper::Result PreconditionChecks(const CWallet& wallet, const CWalletTx& wtx, bool require_mine, std::vector<bilingual_str>& errors) EXCLUSIVE_LOCKS_REQUIRED(wallet.cs_wallet)
26	{
27	    if (wallet.HasWalletSpend(wtx.tx)) {
28	        errors.emplace_back(Untranslated("Transaction has descendants in the wallet"));
29	        return feebumper::Result::INVALID_PARAMETER;
30	    }
31	
32	    {
33	        if (wallet.chain().hasDescendantsInMempool(wtx.GetHash())) {
34	            errors.emplace_back(Untranslated("Transaction has descendants in the mempool"));
35	            return feebumper::Result::INVALID_PARAMETER;
36	        }
37	    }
38	
39	    if (wallet.GetTxDepthInMainChain(wtx) != 0) {
40	        errors.emplace_back(Untranslated("Transaction has been mined, or is conflicted with a mined transaction"));
41	        return feebumper::Result::WALLET_ERROR;
42	    }
43	
44	    if (wtx.mapValue.contains("replaced_by_txid")) {
45	        errors.push_back(Untranslated(strprintf("Cannot bump transaction %s which was already bumped by transaction %s", wtx.GetHash().ToString(), wtx.mapValue.at("replaced_by_txid"))));
46	        return feebumper::Result::WALLET_ERROR;
47	    }
48	
49	    if (require_mine) {
50	        // check that original tx consists entirely of our inputs
51	        // if not, we can't bump the fee, because the wallet has no way of knowing the value of the other inputs (thus the fee)
52	        if (!AllInputsMine(wallet, *wtx.tx)) {
53	            errors.emplace_back(Untranslated("Transaction contains inputs that don't belong to this wallet"));
54	            return feebumper::Result::WALLET_ERROR;
55	        }
56	    }
