161	Result CreateRateBumpTransaction(CWallet& wallet, const Txid& txid, const CCoinControl& coin_control, std::vector<bilingual_str>& errors,
162	                                 CAmount& old_fee, CAmount& new_fee, CMutableTransaction& mtx, bool require_mine, const std::vector<CTxOut>& outputs, std::optional<uint32_t> original_change_index)
163	{
164	    // For now, cannot specify both new outputs to use and an output index to send change
165	    if (!outputs.empty() && original_change_index.has_value()) {
166	        errors.emplace_back(Untranslated("The options 'outputs' and 'original_change_index' are incompatible. You can only either specify a new set of outputs, or designate a change output to be recycled."));
167	        return Result::INVALID_PARAMETER;
168	    }
169	
170	    // We are going to modify coin control later, copy to reuse
171	    CCoinControl new_coin_control(coin_control);
172	
173	    LOCK(wallet.cs_wallet);
174	    errors.clear();
175	    auto it = wallet.mapWallet.find(txid);
176	    if (it == wallet.mapWallet.end()) {
177	        errors.emplace_back(Untranslated("Invalid or non-wallet transaction id"));
178	        return Result::INVALID_ADDRESS_OR_KEY;
179	    }
180	    const CWalletTx& wtx = it->second;
181	
182	    // Make sure that original_change_index is valid
183	    if (original_change_index.has_value() && original_change_index.value() >= wtx.tx->vout.size()) {
184	        errors.emplace_back(Untranslated("Change position is out of range"));
185	        return Result::INVALID_PARAMETER;
186	    }
187	
188	    // Retrieve all of the UTXOs and add them to coin control
189	    // While we're here, calculate the input amount
190	    std::map<COutPoint, Coin> coins;
191	    CAmount input_value = 0;
192	    std::vector<CTxOut> spent_outputs;
193	    for (const CTxIn& txin : wtx.tx->vin) {
194	        coins[txin.prevout]; // Create empty map entry keyed by prevout.
195	    }
196	    wallet.chain().findCoins(coins);
197	    for (const CTxIn& txin : wtx.tx->vin) {
198	        const Coin& coin = coins.at(txin.prevout);
199	        if (coin.out.IsNull()) {
200	            errors.emplace_back(Untranslated(strprintf("%s:%u is already spent", txin.prevout.hash.GetHex(), txin.prevout.n)));
201	            return Result::MISC_ERROR;
202	        }
203	        PreselectedInput& preset_txin = new_coin_control.Select(txin.prevout);
204	        if (!wallet.IsMine(txin.prevout)) {
205	            preset_txin.SetTxOut(coin.out);
206	        }
207	        input_value += coin.out.nValue;
208	        spent_outputs.push_back(coin.out);
209	    }
210	
211	    // Figure out if we need to compute the input weight, and do so if necessary
212	    PrecomputedTransactionData txdata;
213	    txdata.Init(*wtx.tx, std::move(spent_outputs), /* force=*/ true);
214	    for (unsigned int i = 0; i < wtx.tx->vin.size(); ++i) {
215	        const CTxIn& txin = wtx.tx->vin.at(i);
216	        const Coin& coin = coins.at(txin.prevout);
217	
218	        if (new_coin_control.IsExternalSelected(txin.prevout)) {
219	            // For external inputs, we estimate the size using the size of this input
220	            int64_t input_weight = GetTransactionInputWeight(txin);
221	            // Because signatures can have different sizes, we need to figure out all of the
222	            // signature sizes and replace them with the max sized signature.
223	            // In order to do this, we verify the script with a special SignatureChecker which
224	            // will observe the signatures verified and record their sizes.
225	            SignatureWeights weights;
226	            TransactionSignatureChecker tx_checker(wtx.tx.get(), i, coin.out.nValue, txdata, MissingDataBehavior::FAIL);
227	            SignatureWeightChecker size_checker(weights, tx_checker);
228	            VerifyScript(txin.scriptSig, coin.out.scriptPubKey, &txin.scriptWitness, STANDARD_SCRIPT_VERIFY_FLAGS, size_checker);
229	            // Add the difference between max and current to input_weight so that it represents the largest the input could be
230	            input_weight += weights.GetWeightDiffToMax();
231	            new_coin_control.SetInputWeight(txin.prevout, input_weight);
232	        }
233	    }
234	
235	    Result result = PreconditionChecks(wallet, wtx, require_mine, errors);
236	    if (result != Result::OK) {
237	        return result;
238	    }
239	
240	    // Calculate the old output amount.
241	    CAmount output_value = 0;
242	    for (const auto& old_output : wtx.tx->vout) {
243	        output_value += old_output.nValue;
244	    }
245	
246	    old_fee = input_value - output_value;
247	
248	    // Fill in recipients (and preserve a single change key if there
249	    // is one). If outputs vector is non-empty, replace original
250	    // outputs with its contents, otherwise use original outputs.
251	    std::vector<CRecipient> recipients;
252	    CAmount new_outputs_value = 0;
253	    const auto& txouts = outputs.empty() ? wtx.tx->vout : outputs;
254	    for (size_t i = 0; i < txouts.size(); ++i) {
255	        const CTxOut& output = txouts.at(i);
256	        CTxDestination dest;
257	        ExtractDestination(output.scriptPubKey, dest);
258	        if (original_change_index.has_value() ?  original_change_index.value() == i : OutputIsChange(wallet, output)) {
259	            new_coin_control.destChange = dest;
260	        } else {
261	            CRecipient recipient = {dest, output.nValue, false};
262	            recipients.push_back(recipient);
263	        }
264	        new_outputs_value += output.nValue;
265	    }
266	
267	    // If no recipients, means that we are sending coins to a change address
268	    if (recipients.empty()) {
269	        // Just as a sanity check, ensure that the change address exist
270	        if (std::get_if<CNoDestination>(&new_coin_control.destChange)) {
271	            errors.emplace_back(Untranslated("Unable to create transaction. Transaction must have at least one recipient"));
272	            return Result::INVALID_PARAMETER;
273	        }
274	
275	        // Add change as recipient with SFFO flag enabled, so fees are deduced from it.
276	        // If the output differs from the original tx output (because the user customized it) a new change output will be created.
277	        recipients.emplace_back(CRecipient{new_coin_control.destChange, new_outputs_value, /*fSubtractFeeFromAmount=*/true});
278	        new_coin_control.destChange = CNoDestination();
279	    }
280	
281	    if (coin_control.m_feerate) {
282	        // The user provided a feeRate argument.
283	        // We calculate this here to avoid compiler warning on the cs_wallet lock
284	        // We need to make a temporary transaction with no input witnesses as the dummy signer expects them to be empty for external inputs
285	        CMutableTransaction temp_mtx{*wtx.tx};
286	        for (auto& txin : temp_mtx.vin) {
287	            txin.scriptSig.clear();
288	            txin.scriptWitness.SetNull();
289	        }
290	        temp_mtx.vout = txouts;
291	        const int64_t maxTxSize{CalculateMaximumSignedTxSize(CTransaction(temp_mtx), &wallet, &new_coin_control).vsize};
292	        Result res = CheckFeeRate(wallet, temp_mtx, *new_coin_control.m_feerate, maxTxSize, old_fee, errors);
293	        if (res != Result::OK) {
294	            return res;
295	        }
296	    } else {
297	        // The user did not provide a feeRate argument
298	        new_coin_control.m_feerate = EstimateFeeRate(wallet, wtx, old_fee, new_coin_control);
299	    }
300	
301	    // Fill in required inputs we are double-spending(all of them)
302	    // N.B.: bip125 doesn't require all the inputs in the replaced transaction to be
303	    // used in the replacement transaction, but it's very important for wallets to make
304	    // sure that happens. If not, it would be possible to bump a transaction A twice to
305	    // A2 and A3 where A2 and A3 don't conflict (or alternatively bump A to A2 and A2
306	    // to A3 where A and A3 don't conflict). If both later get confirmed then the sender
307	    // has accidentally double paid.
308	    for (const auto& inputs : wtx.tx->vin) {
309	        new_coin_control.Select(COutPoint(inputs.prevout));
310	    }
311	    new_coin_control.m_allow_other_inputs = true;
312	
313	    // We cannot source new unconfirmed inputs(bip125 rule 2)
314	    new_coin_control.m_min_depth = 1;
315	
316	    auto res = CreateTransaction(wallet, recipients, /*change_pos=*/std::nullopt, new_coin_control, false);
317	    if (!res) {
318	        errors.emplace_back(Untranslated("Unable to create transaction.") + Untranslated(" ") + util::ErrorString(res));
319	        return Result::WALLET_ERROR;
320	    }
321	
322	    const auto& txr = *res;
323	    // Write back new fee if successful
324	    new_fee = txr.fee;
325	
326	    // Write back transaction
327	    mtx = CMutableTransaction(*txr.tx);
328	
329	    return Result::OK;
330	}
