246	static OutputType GetOutputType(TxoutType type, bool is_from_p2sh)
247	{
248	    switch (type) {
249	        case TxoutType::WITNESS_V1_TAPROOT:
250	            return OutputType::BECH32M;
251	        case TxoutType::WITNESS_V0_KEYHASH:
252	        case TxoutType::WITNESS_V0_SCRIPTHASH:
253	            if (is_from_p2sh) return OutputType::P2SH_SEGWIT;
254	            else return OutputType::BECH32;
255	        case TxoutType::SCRIPTHASH:
256	        case TxoutType::PUBKEYHASH:
257	            return OutputType::LEGACY;
258	        default:
259	            return OutputType::UNKNOWN;
260	    }
261	}
