1540	void CWallet::blockConnected(const ChainstateRole& role, const interfaces::BlockInfo& block)
1541	{
1542	    if (role.historical) {
1543	        return;
1544	    }
1545	    assert(block.data);
1546	    LOCK(cs_wallet);
1547	
1548	    // Update the best block in memory first. This will set the best block's height, which is
1549	    // needed by MarkConflicted.
1550	    SetLastBlockProcessedInMem(block.height, block.hash);
1551	
1552	    // No need to scan block if it was created before the wallet birthday.
1553	    // Uses chain max time and twice the grace period to adjust time for block time variability.
1554	    if (block.chain_time_max < m_birth_time.load() - (TIMESTAMP_WINDOW * 2)) return;
1555	
1556	    // Scan block
1557	    bool wallet_updated = false;
1558	    for (size_t index = 0; index < block.data->vtx.size(); index++) {
1559	        wallet_updated |= SyncTransaction(block.data->vtx[index], TxStateConfirmed{block.hash, block.height, static_cast<int>(index)});
1560	        transactionRemovedFromMempool(block.data->vtx[index], MemPoolRemovalReason::BLOCK);
1561	    }
1562	
1563	    // Update on disk if this block resulted in us updating a tx, or periodically every 144 blocks (~1 day)
1564	    if (wallet_updated || block.height % 144 == 0) {
1565	        WriteBestBlock();
1566	    }
1567	}
