1569	void CWallet::blockDisconnected(const interfaces::BlockInfo& block)
1570	{
1571	    assert(block.data);
1572	    LOCK(cs_wallet);
1573	
1574	    // At block disconnection, this will change an abandoned transaction to
1575	    // be unconfirmed, whether or not the transaction is added back to the mempool.
1576	    // User may have to call abandontransaction again. It may be addressed in the
1577	    // future with a stickier abandoned state or even removing abandontransaction call.
1578	    int disconnect_height = block.height;
1579	
1580	    for (size_t index = 0; index < block.data->vtx.size(); index++) {
1581	        const CTransactionRef& ptx = block.data->vtx[index];
1582	        // Coinbase transactions are not only inactive but also abandoned,
1583	        // meaning they should never be relayed standalone via the p2p protocol.
1584	        SyncTransaction(ptx, TxStateInactive{/*abandoned=*/index == 0});
1585	
1586	        for (const CTxIn& tx_in : ptx->vin) {
1587	            // No other wallet transactions conflicted with this transaction
1588	            if (!mapTxSpends.contains(tx_in.prevout)) continue;
1589	
1590	            std::pair<TxSpends::const_iterator, TxSpends::const_iterator> range = mapTxSpends.equal_range(tx_in.prevout);
1591	
1592	            // For all of the spends that conflict with this transaction
1593	            for (TxSpends::const_iterator _it = range.first; _it != range.second; ++_it) {
1594	                CWalletTx& wtx = mapWallet.find(_it->second)->second;
1595	
1596	                if (!wtx.isBlockConflicted()) continue;
1597	
1598	                auto try_updating_state = [&](CWalletTx& tx) {
1599	                    if (!tx.isBlockConflicted()) return TxUpdate::UNCHANGED;
1600	                    if (tx.state<TxStateBlockConflicted>()->conflicting_block_height >= disconnect_height) {
1601	                        tx.m_state = TxStateInactive{};
1602	                        return TxUpdate::CHANGED;
1603	                    }
1604	                    return TxUpdate::UNCHANGED;
1605	                };
1606	
1607	                RecursiveUpdateTxState(wtx.tx->GetHash(), try_updating_state);
1608	            }
1609	        }
1610	    }
1611	
1612	    // Update the best block
1613	    SetLastBlockProcessed(block.height - 1, *Assert(block.prev_hash));
1614	}
