1819	/**
1820	 * Scan active chain for relevant transactions after importing keys. This should
1821	 * be called whenever new keys are added to the wallet, with the oldest key
1822	 * creation time.
1823	 *
1824	 * @return Earliest timestamp that could be successfully scanned from. Timestamp
1825	 * returned will be higher than startTime if relevant blocks could not be read.
1826	 */
1827	int64_t CWallet::RescanFromTime(int64_t startTime, const WalletRescanReserver& reserver)
1828	{
1829	    // Find starting block. May be null if nCreateTime is greater than the
1830	    // highest blockchain timestamp, in which case there is nothing that needs
1831	    // to be scanned.
1832	    int start_height = 0;
1833	    uint256 start_block;
1834	    bool start = chain().findFirstBlockWithTimeAndHeight(startTime - TIMESTAMP_WINDOW, 0, FoundBlock().hash(start_block).height(start_height));
1835	    WalletLogPrintf("%s: Rescanning last %i blocks\n", __func__, start ? WITH_LOCK(cs_wallet, return GetLastBlockHeight()) - start_height + 1 : 0);
1836	
1837	    if (start) {
1838	        // TODO: this should take into account failure by ScanResult::USER_ABORT
1839	        ScanResult result = ScanForWalletTransactions(start_block, start_height, /*max_height=*/{}, reserver, /*save_progress=*/false);
1840	        if (result.status == ScanResult::FAILURE) {
1841	            int64_t time_max;
1842	            CHECK_NONFATAL(chain().findBlock(result.last_failed_block, FoundBlock().maxTime(time_max)));
1843	            return time_max + TIMESTAMP_WINDOW + 1;
1844	        }
1845	    }
1846	    return startTime;
1847	}
1848	
1849	/**
1850	 * Scan the block chain (starting in start_block) for transactions
1851	 * from or to us. If max_height is not set, the
1852	 * mempool will be scanned as well.
1853	 *
1854	 * @param[in] start_block Scan starting block. If block is not on the active
1855	 *                        chain, the scan will return SUCCESS immediately.
1856	 * @param[in] start_height Height of start_block
1857	 * @param[in] max_height  Optional max scanning height. If unset there is
1858	 *                        no maximum and scanning can continue to the tip
1859	 *
1860	 * @return ScanResult returning scan information and indicating success or
1861	 *         failure. Return status will be set to SUCCESS if scan was
1862	 *         successful. FAILURE if a complete rescan was not possible (due to
1863	 *         pruning or corruption). USER_ABORT if the rescan was aborted before
1864	 *         it could complete.
1865	 *
1866	 * @pre Caller needs to make sure start_block (and the optional stop_block) are on
1867	 * the main chain after to the addition of any new keys you want to detect
1868	 * transactions for.
1869	 */
1870	CWallet::ScanResult CWallet::ScanForWalletTransactions(const uint256& start_block, int start_height, std::optional<int> max_height, const WalletRescanReserver& reserver, const bool save_progress)
1871	{
1872	    constexpr auto INTERVAL_TIME{60s};
1873	    auto current_time{reserver.now()};
1874	    auto start_time{reserver.now()};
1875	
1876	    assert(reserver.isReserved());
1877	
1878	    uint256 block_hash = start_block;
1879	    ScanResult result;
1880	
1881	    std::unique_ptr<FastWalletRescanFilter> fast_rescan_filter;
1882	    if (chain().hasBlockFilterIndex(BlockFilterType::BASIC)) fast_rescan_filter = std::make_unique<FastWalletRescanFilter>(*this);
1883	
1884	    WalletLogPrintf("Rescan started from block %s... (%s)\n", start_block.ToString(),
1885	                    fast_rescan_filter ? "fast variant using block filters" : "slow variant inspecting all blocks");
1886	
1887	    ShowProgress(strprintf("[%s] %s", DisplayName(), _("Rescanning…")), 0); // show rescan progress in GUI as dialog or on splashscreen, if rescan required on startup (e.g. due to corruption)
1888	    uint256 tip_hash = WITH_LOCK(cs_wallet, return GetLastBlockHash());
1889	    uint256 end_hash = tip_hash;
1890	    if (max_height) chain().findAncestorByHeight(tip_hash, *max_height, FoundBlock().hash(end_hash));
1891	    double progress_begin = chain().guessVerificationProgress(block_hash);
1892	    double progress_end = chain().guessVerificationProgress(end_hash);
1893	    double progress_current = progress_begin;
1894	    int block_height = start_height;
1895	    while (!fAbortRescan && !chain().shutdownRequested()) {
1896	        if (progress_end - progress_begin > 0.0) {
1897	            m_scanning_progress = (progress_current - progress_begin) / (progress_end - progress_begin);
1898	        } else { // avoid divide-by-zero for single block scan range (i.e. start and stop hashes are equal)
1899	            m_scanning_progress = 0;
1900	        }
1901	        if (block_height % 100 == 0 && progress_end - progress_begin > 0.0) {
1902	            ShowProgress(strprintf("[%s] %s", DisplayName(), _("Rescanning…")), std::max(1, std::min(99, (int)(m_scanning_progress * 100))));
1903	        }
1904	
1905	        bool next_interval = reserver.now() >= current_time + INTERVAL_TIME;
1906	        if (next_interval) {
1907	            current_time = reserver.now();
1908	            WalletLogPrintf("Still rescanning. At block %d. Progress=%f\n", block_height, progress_current);
1909	        }
1910	
1911	        bool fetch_block{true};
1912	        if (fast_rescan_filter) {
1913	            fast_rescan_filter->UpdateIfNeeded();
1914	            auto matches_block{fast_rescan_filter->MatchesBlock(block_hash)};
1915	            if (matches_block.has_value()) {
1916	                if (*matches_block) {
1917	                    LogDebug(BCLog::SCAN, "Fast rescan: inspect block %d [%s] (filter matched)\n", block_height, block_hash.ToString());
1918	                } else {
1919	                    result.last_scanned_block = block_hash;
1920	                    result.last_scanned_height = block_height;
1921	                    fetch_block = false;
1922	                }
1923	            } else {
1924	                LogDebug(BCLog::SCAN, "Fast rescan: inspect block %d [%s] (WARNING: block filter not found!)\n", block_height, block_hash.ToString());
1925	            }
1926	        }
1927	
1928	        // Find next block separately from reading data above, because reading
1929	        // is slow and there might be a reorg while it is read.
1930	        bool block_still_active = false;
1931	        bool next_block = false;
1932	        uint256 next_block_hash;
1933	        chain().findBlock(block_hash, FoundBlock().inActiveChain(block_still_active).nextBlock(FoundBlock().inActiveChain(next_block).hash(next_block_hash)));
1934	
1935	        if (fetch_block) {
1936	            // Read block data and locator if needed (the locator is usually null unless we need to save progress)
1937	            CBlock block;
1938	            CBlockLocator loc;
1939	            // Find block
1940	            FoundBlock found_block{FoundBlock().data(block)};
1941	            if (save_progress && next_interval) found_block.locator(loc);
1942	            chain().findBlock(block_hash, found_block);
1943	
1944	            if (!block.IsNull()) {
1945	                LOCK(cs_wallet);
1946	                if (!block_still_active) {
1947	                    // Abort scan if current block is no longer active, to prevent
1948	                    // marking transactions as coming from the wrong block.
1949	                    result.last_failed_block = block_hash;
1950	                    result.status = ScanResult::FAILURE;
1951	                    break;
1952	                }
1953	                for (size_t posInBlock = 0; posInBlock < block.vtx.size(); ++posInBlock) {
1954	                    SyncTransaction(block.vtx[posInBlock], TxStateConfirmed{block_hash, block_height, static_cast<int>(posInBlock)}, /*rescanning_old_block=*/true);
1955	                }
1956	                // scan succeeded, record block as most recent successfully scanned
1957	                result.last_scanned_block = block_hash;
1958	                result.last_scanned_height = block_height;
1959	
1960	                if (!loc.IsNull()) {
1961	                    WalletLogPrintf("Saving scan progress %d.\n", block_height);
1962	                    WalletBatch batch(GetDatabase());
1963	                    batch.WriteBestBlock(loc);
1964	                }
1965	            } else {
1966	                // could not scan block, keep scanning but record this block as the most recent failure
1967	                result.last_failed_block = block_hash;
1968	                result.status = ScanResult::FAILURE;
1969	            }
1970	        }
1971	        if (max_height && block_height >= *max_height) {
1972	            break;
1973	        }
1974	        // If rescanning was triggered with cs_wallet permanently locked (AttachChain), additional blocks that were connected during the rescan
1975	        // aren't processed here but will be processed with the pending blockConnected notifications after the lock is released.
1976	        // If rescanning without a permanent cs_wallet lock, additional blocks that were added during the rescan will be re-processed if
1977	        // the notification was processed and the last block height was updated.
1978	        if (block_height >= WITH_LOCK(cs_wallet, return GetLastBlockHeight())) {
1979	            break;
1980	        }
1981	
1982	        {
1983	            if (!next_block) {
1984	                // break successfully when rescan has reached the tip, or
1985	                // previous block is no longer on the chain due to a reorg
1986	                break;
1987	            }
1988	
1989	            // increment block and verification progress
1990	            block_hash = next_block_hash;
1991	            ++block_height;
1992	            progress_current = chain().guessVerificationProgress(block_hash);
1993	
1994	            // handle updated tip hash
1995	            const uint256 prev_tip_hash = tip_hash;
1996	            tip_hash = WITH_LOCK(cs_wallet, return GetLastBlockHash());
1997	            if (!max_height && prev_tip_hash != tip_hash) {
1998	                // in case the tip has changed, update progress max
1999	                progress_end = chain().guessVerificationProgress(tip_hash);

2500	    const std::string& encoded_dest = EncodeDestination(address);
2501	    if (new_purpose && !batch.WritePurpose(encoded_dest, PurposeToString(*new_purpose))) {
2502	        WalletLogPrintf("Error: fail to write address book 'purpose' entry\n");
2503	        return false;
2504	    }
2505	    if (!batch.WriteName(encoded_dest, strName)) {
2506	        WalletLogPrintf("Error: fail to write address book 'name' entry\n");
2507	        return false;
2508	    }
2509	
2510	    // In very old wallets, address purpose may not be recorded so we derive it from IsMine
2511	    NotifyAddressBookChanged(address, strName, is_mine,
2512	                             purpose.value_or(is_mine ? AddressPurpose::RECEIVE : AddressPurpose::SEND),
2513	                             (fUpdated ? CT_UPDATED : CT_NEW));
2514	    return true;
2515	}
