2529	
2530	bool CWallet::DelAddressBookWithDB(WalletBatch& batch, const CTxDestination& address)
2531	{
2532	    const std::string& dest = EncodeDestination(address);
2533	    {
2534	        LOCK(cs_wallet);
2535	        // If we want to delete receiving addresses, we should avoid calling EraseAddressData because it will delete the previously_spent value. Could instead just erase the label so it becomes a change address, and keep the data.
2536	        // NOTE: This isn't a problem for sending addresses because they don't have any data that needs to be kept.
2537	        // When adding new address data, it should be considered here whether to retain or delete it.
2538	        if (IsMine(address)) {
2539	            WalletLogPrintf("%s called with IsMine address, NOT SUPPORTED. Please report this bug! %s\n", __func__, CLIENT_BUGREPORT);
2540	            return false;
2541	        }
2542	        // Delete data rows associated with this address
2543	        if (!batch.EraseAddressData(address)) {
2544	            WalletLogPrintf("Error: cannot erase address book entry data\n");
2545	            return false;
2546	        }
2547	
2548	        // Delete purpose entry
2549	        if (!batch.ErasePurpose(dest)) {
2550	            WalletLogPrintf("Error: cannot erase address book entry purpose\n");
2551	            return false;
2552	        }
2553	
2554	        // Delete name entry
2555	        if (!batch.EraseName(dest)) {
2556	            WalletLogPrintf("Error: cannot erase address book entry name\n");
2557	            return false;
2558	        }
2559	
2560	        // finally, remove it from the map
2561	        m_address_book.erase(address);
2562	    }
2563	
2564	    // All good, signal changes
2565	    NotifyAddressBookChanged(address, "", /*is_mine=*/false, AddressPurpose::SEND, CT_DELETED);
2566	    return true;
2567	}
