2790	/**
2791	 * Compute smart timestamp for a transaction being added to the wallet.
2792	 *
2793	 * Logic:
2794	 * - If sending a transaction, assign its timestamp to the current time.
2795	 * - If receiving a transaction outside a block, assign its timestamp to the
2796	 *   current time.
2797	 * - If receiving a transaction during a rescanning process, assign all its
2798	 *   (not already known) transactions' timestamps to the block time.
2799	 * - If receiving a block with a future timestamp, assign all its (not already
2800	 *   known) transactions' timestamps to the current time.
2801	 * - If receiving a block with a past timestamp, before the most recent known
2802	 *   transaction (that we care about), assign all its (not already known)
2803	 *   transactions' timestamps to the same timestamp as that most-recent-known
2804	 *   transaction.
2805	 * - If receiving a block with a past timestamp, but after the most recent known
2806	 *   transaction, assign all its (not already known) transactions' timestamps to
2807	 *   the block time.
2808	 *
2809	 * For more information see CWalletTx::nTimeSmart,
2810	 * https://bitcointalk.org/?topic=54527, or
2811	 * https://github.com/bitcoin/bitcoin/pull/1393.
2812	 */
2813	unsigned int CWallet::ComputeTimeSmart(const CWalletTx& wtx, bool rescanning_old_block) const
2814	{
2815	    std::optional<uint256> block_hash;
2816	    if (auto* conf = wtx.state<TxStateConfirmed>()) {
2817	        block_hash = conf->confirmed_block_hash;
2818	    } else if (auto* conf = wtx.state<TxStateBlockConflicted>()) {
2819	        block_hash = conf->conflicting_block_hash;
2820	    }
2821	
2822	    unsigned int nTimeSmart = wtx.nTimeReceived;
2823	    if (block_hash) {
2824	        int64_t blocktime;
2825	        int64_t block_max_time;
2826	        if (chain().findBlock(*block_hash, FoundBlock().time(blocktime).maxTime(block_max_time))) {
2827	            if (rescanning_old_block) {
2828	                nTimeSmart = block_max_time;
2829	            } else {
2830	                int64_t latestNow = wtx.nTimeReceived;
2831	                int64_t latestEntry = 0;
2832	
2833	                // Tolerate times up to the last timestamp in the wallet not more than 5 minutes into the future
2834	                int64_t latestTolerated = latestNow + 300;
2835	                const TxItems& txOrdered = wtxOrdered;
2836	                for (auto it = txOrdered.rbegin(); it != txOrdered.rend(); ++it) {
2837	                    CWalletTx* const pwtx = it->second;
2838	                    if (pwtx == &wtx) {
2839	                        continue;
2840	                    }
2841	                    int64_t nSmartTime;
2842	                    nSmartTime = pwtx->nTimeSmart;
2843	                    if (!nSmartTime) {
2844	                        nSmartTime = pwtx->nTimeReceived;
2845	                    }
2846	                    if (nSmartTime <= latestTolerated) {
2847	                        latestEntry = nSmartTime;
2848	                        if (nSmartTime > latestNow) {
2849	                            latestNow = nSmartTime;
2850	                        }
2851	                        break;
2852	                    }
2853	                }
2854	
2855	                nTimeSmart = std::max(latestEntry, std::min(blocktime, latestNow));
2856	            }
2857	        } else {
2858	            WalletLogPrintf("%s: found %s in block %s not in index\n", __func__, wtx.GetHash().ToString(), block_hash->ToString());
2859	        }
2860	    }
2861	    return nTimeSmart;
2862	}
