2919	util::Result<fs::path> GetWalletPath(const std::string& name)
2920	{
2921	    const fs::path name_path = fs::PathFromString(name);
2922	
2923	    // 'name' must be a normalized path, i.e. no . or .. except at the root
2924	    if (name_path != name_path.lexically_normal()) {
2925	        return util::Error{Untranslated("Wallet name given as a path must be normalized")};
2926	    }
2927	
2928	    // 'name' cannot begin with ./ or ../
2929	    if (!name_path.empty() && (*name_path.begin() == fs::PathFromString(".") || *name_path.begin() == fs::PathFromString(".."))) {
2930	        return util::Error{Untranslated("Wallet name given as a relative path cannot begin with ./ or ../, for wallets not in the walletdir, please use an absolute path.")};
2931	    }
2932	
2933	    // Disallow path at root
2934	    if (name_path.has_root_path() && name_path.root_path() == name_path) {
2935	        return util::Error{Untranslated("Wallet name cannot be the root path")};
2936	    }
2937	
2938	    // Do some checking on wallet path. It should be either a:
2939	    //
2940	    // 1. Path where a directory can be created.
2941	    // 2. Path to an existing directory.
2942	    // 3. Path to a symlink to a directory.
2943	    // 4. For backwards compatibility, the name of a data file in -walletdir.
2944	    const fs::path wallet_path = fsbridge::AbsPathJoin(GetWalletDir(), name_path);
2945	    fs::file_type path_type = fs::symlink_status(wallet_path).type();
2946	    if (!(path_type == fs::file_type::not_found || path_type == fs::file_type::directory ||
2947	          (path_type == fs::file_type::symlink && fs::is_directory(wallet_path)) ||
2948	          (path_type == fs::file_type::regular && name_path.filename() == name_path))) {
2949	        return util::Error{Untranslated(strprintf(
2950	              "Invalid -wallet path '%s'. -wallet path should point to a directory where wallet.dat and "
2951	              "database/log.?????????? files can be stored, a location where such a directory could be created, "
2952	              "or (for backwards compatibility) the name of an existing data file in -walletdir (%s)",
2953	              name, fs::quoted(fs::PathToString(GetWalletDir()))))};
2954	    }
2955	    return wallet_path;
2956	}
