3638	void CWallet::SetupDescriptorScriptPubKeyMans()
3639	{
3640	    AssertLockHeld(cs_wallet);
3641	
3642	    if (!IsWalletFlagSet(WALLET_FLAG_EXTERNAL_SIGNER)) {
3643	        if (!RunWithinTxn(GetDatabase(), /*process_desc=*/"setup descriptors", [&](WalletBatch& batch) EXCLUSIVE_LOCKS_REQUIRED(cs_wallet){
3644	            SetupOwnDescriptorScriptPubKeyMans(batch);
3645	            return true;
3646	        })) throw std::runtime_error("Error: cannot process db transaction for descriptors setup");
3647	    } else {
3648	        auto signer = ExternalSignerScriptPubKeyMan::GetExternalSigner();
3649	        if (!signer) throw std::runtime_error(util::ErrorString(signer).original);
3650	
3651	        // TODO: add account parameter
3652	        int account = 0;
3653	        UniValue signer_res = signer->GetDescriptors(account);
3654	
3655	        if (!signer_res.isObject()) throw std::runtime_error(std::string(__func__) + ": Unexpected result");
3656	
3657	        WalletBatch batch(GetDatabase());
3658	        if (!batch.TxnBegin()) throw std::runtime_error("Error: cannot create db transaction for descriptors import");
3659	
3660	        for (bool internal : {false, true}) {
3661	            const UniValue& descriptor_vals = signer_res.find_value(internal ? "internal" : "receive");
3662	            if (!descriptor_vals.isArray()) throw std::runtime_error(std::string(__func__) + ": Unexpected result");
3663	            for (const UniValue& desc_val : descriptor_vals.get_array().getValues()) {
3664	                const std::string& desc_str = desc_val.getValStr();
3665	                FlatSigningProvider keys;
3666	                std::string desc_error;
3667	                auto descs = Parse(desc_str, keys, desc_error, false);
3668	                if (descs.empty()) {
3669	                    throw std::runtime_error(std::string(__func__) + ": Invalid descriptor \"" + desc_str + "\" (" + desc_error + ")");
3670	                }
3671	                auto& desc = descs.at(0);
3672	                if (!desc->GetOutputType()) {
3673	                    continue;
3674	                }
3675	                OutputType t =  *desc->GetOutputType();
3676	                auto spk_manager = ExternalSignerScriptPubKeyMan::CreateNew(*this, batch, m_keypool_size, std::move(desc));
3677	                uint256 id = spk_manager->GetID();
3678	                AddScriptPubKeyMan(id, std::move(spk_manager));
3679	                AddActiveScriptPubKeyManWithDb(batch, id, t, internal);
3680	            }
3681	        }
3682	
3683	        // Ensure imported descriptors are committed to disk
3684	        if (!batch.TxnCommit()) throw std::runtime_error("Error: cannot commit db transaction for descriptors import");
3685	    }
3686	}
