3714	void CWallet::LoadActiveScriptPubKeyMan(uint256 id, OutputType type, bool internal)
3715	{
3716	    // Activating ScriptPubKeyManager for a given output and change type is incompatible with legacy wallets.
3717	    // Legacy wallets have only one ScriptPubKeyManager and it's active for all output and change types.
3718	    Assert(IsWalletFlagSet(WALLET_FLAG_DESCRIPTORS));
3719	
3720	    WalletLogPrintf("Setting spkMan to active: id = %s, type = %s, internal = %s\n", id.ToString(), FormatOutputType(type), internal ? "true" : "false");
3721	    auto& spk_mans = internal ? m_internal_spk_managers : m_external_spk_managers;
3722	    auto& spk_mans_other = internal ? m_external_spk_managers : m_internal_spk_managers;
3723	    auto spk_man = m_spk_managers.at(id).get();
3724	    spk_mans[type] = spk_man;
3725	
3726	    const auto it = spk_mans_other.find(type);
3727	    if (it != spk_mans_other.end() && it->second == spk_man) {
3728	        spk_mans_other.erase(type);
3729	    }
3730	
