3734	void CWallet::DeactivateScriptPubKeyMan(uint256 id, OutputType type, bool internal)
3735	{
3736	    auto spk_man = GetScriptPubKeyMan(type, internal);
3737	    if (spk_man != nullptr && spk_man->GetID() == id) {
3738	        WalletLogPrintf("Deactivate spkMan: id = %s, type = %s, internal = %s\n", id.ToString(), FormatOutputType(type), internal ? "true" : "false");
3739	        WalletBatch batch(GetDatabase());
3740	        if (!batch.EraseActiveScriptPubKeyMan(static_cast<uint8_t>(type), internal)) {
3741	            throw std::runtime_error(std::string(__func__) + ": erasing active ScriptPubKeyMan id failed");
3742	        }
3743	
3744	        auto& spk_mans = internal ? m_internal_spk_managers : m_external_spk_managers;
