3756	        // Try to downcast to DescriptorScriptPubKeyMan then check if the descriptors match
3757	        DescriptorScriptPubKeyMan* spk_manager = dynamic_cast<DescriptorScriptPubKeyMan*>(spk_man_pair->second.get());
3758	        if (spk_manager != nullptr && spk_manager->HasWalletDescriptor(desc)) {
