3785	util::Result<std::reference_wrapper<DescriptorScriptPubKeyMan>> CWallet::AddWalletDescriptor(WalletDescriptor& desc, const FlatSigningProvider& signing_provider, const std::string& label, bool internal)
3786	{
3787	    AssertLockHeld(cs_wallet);
3788	
3789	    Assert(IsWalletFlagSet(WALLET_FLAG_DESCRIPTORS));
3790	
3791	    auto spk_man = GetDescriptorScriptPubKeyMan(desc);
3792	    if (spk_man) {
3793	        WalletLogPrintf("Update existing descriptor: %s\n", desc.descriptor->ToString());
3794	        if (auto spkm_res = spk_man->UpdateWalletDescriptor(desc, signing_provider); !spkm_res) {
3795	            return util::Error{util::ErrorString(spkm_res)};
3796	        }
3797	    } else {
3798	        auto new_spk_man = DescriptorScriptPubKeyMan::CreateFromImport(*this, desc, m_keypool_size, signing_provider);
3799	        spk_man = new_spk_man.get();
3800	
3801	        // Save the descriptor to memory
3802	        uint256 id = new_spk_man->GetID();
3803	        AddScriptPubKeyMan(id, std::move(new_spk_man));
3804	    }
3805	
3806	    // Apply the label if necessary
3807	    // Note: we disable labels for descriptors that are ranged or that don't produce output scripts (i.e. unused())
3808	    if (!desc.descriptor->IsRange() && desc.descriptor->HasScripts()) {
3809	        auto script_pub_keys = spk_man->GetScriptPubKeys();
3810	        if (script_pub_keys.empty()) {
3811	            return util::Error{_("Could not generate scriptPubKeys (cache is empty)")};
3812	        }
3813	
3814	        if (!internal) {
3815	            for (const auto& script : script_pub_keys) {
3816	                CTxDestination dest;
3817	                if (ExtractDestination(script, dest)) {
3818	                    SetAddressBook(dest, label, AddressPurpose::RECEIVE);
3819	                }
3820	            }
3821	        }
3822	    }
3823	
3824	    // Save the descriptor to DB
3825	    spk_man->WriteDescriptor();
3826	
3827	    // Break balance caches so that outputs that are now IsMine in already known txs will be included in the balance
3828	    MarkDirty();
3829	
3830	    return std::reference_wrapper(*spk_man);
3831	}
