3833	bool CWallet::MigrateToSQLite(bilingual_str& error)
3834	{
3835	    AssertLockHeld(cs_wallet);
3836	
3837	    WalletLogPrintf("Migrating wallet storage database from BerkeleyDB to SQLite.\n");
3838	
3839	    if (m_database->Format() == "sqlite") {
3840	        error = _("Error: This wallet already uses SQLite");
3841	        return false;
3842	    }
3843	
3844	    // Get all of the records for DB type migration
3845	    std::unique_ptr<DatabaseBatch> batch = m_database->MakeBatch();
3846	    std::unique_ptr<DatabaseCursor> cursor = batch->GetNewCursor();
3847	    std::vector<std::pair<SerializeData, SerializeData>> records;
3848	    if (!cursor) {
3849	        error = _("Error: Unable to begin reading all records in the database");
3850	        return false;
3851	    }
3852	    DatabaseCursor::Status status = DatabaseCursor::Status::FAIL;
3853	    while (true) {
3854	        DataStream ss_key{};
3855	        DataStream ss_value{};
3856	        status = cursor->Next(ss_key, ss_value);
3857	        if (status != DatabaseCursor::Status::MORE) {
3858	            break;
3859	        }
3860	        SerializeData key(ss_key.begin(), ss_key.end());
3861	        SerializeData value(ss_value.begin(), ss_value.end());
3862	        records.emplace_back(key, value);
3863	    }
3864	    cursor.reset();
3865	    batch.reset();
3866	    if (status != DatabaseCursor::Status::DONE) {
3867	        error = _("Error: Unable to read all records in the database");
3868	        return false;
3869	    }
3870	
3871	    // Close this database and delete the file
3872	    fs::path db_path = fs::PathFromString(m_database->Filename());
3873	    m_database->Close();
3874	    fs::remove(db_path);
3875	
3876	    // Generate the path for the location of the migrated wallet
3877	    // Wallets that are plain files rather than wallet directories will be migrated to be wallet directories.
3878	    const fs::path wallet_path = fsbridge::AbsPathJoin(GetWalletDir(), fs::PathFromString(m_name));
3879	
3880	    // Make new DB
3881	    DatabaseOptions opts;
3882	    opts.require_create = true;
3883	    opts.require_format = DatabaseFormat::SQLITE;
3884	    DatabaseStatus db_status;
3885	    std::unique_ptr<WalletDatabase> new_db = MakeDatabase(wallet_path, opts, db_status, error);
3886	    assert(new_db); // This is to prevent doing anything further with this wallet. The original file was deleted, but a backup exists.
3887	    m_database.reset();
3888	    m_database = std::move(new_db);
3889	
3890	    // Write existing records into the new DB
3891	    batch = m_database->MakeBatch();
3892	    bool began = batch->TxnBegin();
3893	    assert(began); // This is a critical error, the new db could not be written to. The original db exists as a backup, but we should not continue execution.
3894	    for (const auto& [key, value] : records) {
3895	        if (!batch->Write(std::span{key}, std::span{value})) {
3896	            batch->TxnAbort();
3897	            m_database->Close();
3898	            fs::remove(m_database->Filename());
3899	            assert(false); // This is a critical error, the new db could not be written to. The original db exists as a backup, but we should not continue execution.
3900	        }
3901	    }
3902	    bool committed = batch->TxnCommit();
3903	    assert(committed); // This is a critical error, the new db could not be written to. The original db exists as a backup, but we should not continue execution.
3904	    return true;
3905	}
