3925	
3926	util::Result<void> CWallet::ApplyMigrationData(WalletBatch& local_wallet_batch, MigrationData& data)
3927	{
3928	    AssertLockHeld(cs_wallet);
3929	
3930	    LegacyDataSPKM* legacy_spkm = GetLegacyDataSPKM();
3931	    if (!Assume(legacy_spkm)) {
3932	        // This shouldn't happen
3933	        return util::Error{Untranslated(STR_INTERNAL_BUG("Error: Legacy wallet data missing"))};
3934	    }
3935	
3936	    // Note: when the legacy wallet has no spendable scripts, it must be empty at the end of the process.
3937	    bool has_spendable_material = !data.desc_spkms.empty() || data.master_key.key.IsValid();
3938	
3939	    // Get all invalid or non-watched scripts that will not be migrated
3940	    std::set<CTxDestination> not_migrated_dests;
3941	    for (const auto& script : legacy_spkm->GetNotMineScriptPubKeys()) {
3942	        CTxDestination dest;
3943	        if (ExtractDestination(script, dest)) not_migrated_dests.emplace(dest);
3944	    }
3945	
3946	    // When the legacy wallet has no spendable scripts, the main wallet will be empty, leaving its script cache empty as well.
3947	    // The watch-only and/or solvable wallet(s) will contain the scripts in their respective caches.
3948	    if (!data.desc_spkms.empty()) Assume(!m_cached_spks.empty());
3949	    if (!data.watch_descs.empty()) Assume(!data.watchonly_wallet->m_cached_spks.empty());
3950	    if (!data.solvable_descs.empty()) Assume(!data.solvable_wallet->m_cached_spks.empty());
3951	
3952	    for (auto& desc_spkm : data.desc_spkms) {
3953	        if (m_spk_managers.contains(desc_spkm->GetID())) {
3954	            return util::Error{_("Error: Duplicate descriptors created during migration. Your wallet may be corrupted.")};
3955	        }
3956	        uint256 id = desc_spkm->GetID();
3957	        AddScriptPubKeyMan(id, std::move(desc_spkm));
3958	    }
3959	
3960	    // Remove the LegacyScriptPubKeyMan from disk
3961	    if (!legacy_spkm->DeleteRecordsWithDB(local_wallet_batch)) {
3962	        return util::Error{_("Error: cannot remove legacy wallet records")};
3963	    }
3964	
3965	    // Remove the LegacyScriptPubKeyMan from memory
3966	    m_spk_managers.erase(legacy_spkm->GetID());
3967	    m_external_spk_managers.clear();
3968	    m_internal_spk_managers.clear();
3969	
3970	    // Setup new descriptors (only if we are migrating any key material)
3971	    SetWalletFlagWithDB(local_wallet_batch, WALLET_FLAG_DESCRIPTORS | WALLET_FLAG_LAST_HARDENED_XPUB_CACHED);
3972	    if (has_spendable_material && !IsWalletFlagSet(WALLET_FLAG_DISABLE_PRIVATE_KEYS)) {
3973	        // Use the existing master key if we have it
3974	        if (data.master_key.key.IsValid()) {
3975	            SetupDescriptorScriptPubKeyMans(local_wallet_batch, data.master_key);
3976	        } else {
3977	            // Setup with a new seed if we don't.
3978	            SetupOwnDescriptorScriptPubKeyMans(local_wallet_batch);
3979	        }
3980	    }
3981	
3982	    // Get best block locator so that we can copy it to the watchonly and solvables
3983	    // Note: The best block locator was introduced in #152 so ancient wallets do not have it
3984	    CBlockLocator best_block_locator;
3985	    (void)local_wallet_batch.ReadBestBlock(best_block_locator);
3986	
3987	    // Update m_txos to match the descriptors remaining in this wallet
3988	    m_txos.clear();
3989	    RefreshAllTXOs();
3990	
3991	    // Check if the transactions in the wallet are still ours. Either they belong here, or they belong in the watchonly wallet.
3992	    // We need to go through these in the tx insertion order so that lookups to spends works.
3993	    std::vector<Txid> txids_to_delete;
3994	    std::unique_ptr<WalletBatch> watchonly_batch;
3995	    if (data.watchonly_wallet) {
3996	        watchonly_batch = std::make_unique<WalletBatch>(data.watchonly_wallet->GetDatabase());
3997	        if (!watchonly_batch->TxnBegin()) return util::Error{strprintf(_("Error: database transaction cannot be executed for wallet %s"), data.watchonly_wallet->GetName())};
3998	        // Copy the next tx order pos to the watchonly wallet
3999	        LOCK(data.watchonly_wallet->cs_wallet);

4000	        data.watchonly_wallet->nOrderPosNext = nOrderPosNext;
4001	        watchonly_batch->WriteOrderPosNext(data.watchonly_wallet->nOrderPosNext);
4002	        // Write the locator record. An empty locator is valid and triggers rescan on load.
4003	        if (!watchonly_batch->WriteBestBlock(best_block_locator)) {
4004	            return util::Error{_("Error: Unable to write watchonly wallet best block locator record")};
4005	        }
4006	    }
4007	    std::unique_ptr<WalletBatch> solvables_batch;
4008	    if (data.solvable_wallet) {
4009	        solvables_batch = std::make_unique<WalletBatch>(data.solvable_wallet->GetDatabase());
4010	        if (!solvables_batch->TxnBegin()) return util::Error{strprintf(_("Error: database transaction cannot be executed for wallet %s"), data.solvable_wallet->GetName())};
4011	        // Write the locator record. An empty locator is valid and triggers rescan on load.
4012	        if (!solvables_batch->WriteBestBlock(best_block_locator)) {
4013	            return util::Error{_("Error: Unable to write solvable wallet best block locator record")};
4014	        }
4015	    }
4016	    for (const auto& [_pos, wtx] : wtxOrdered) {
4017	        // Check it is the watchonly wallet's
4018	        // solvable_wallet doesn't need to be checked because transactions for those scripts weren't being watched for
4019	        bool is_mine = IsMine(*wtx->tx) || IsFromMe(*wtx->tx);
4020	        if (data.watchonly_wallet) {
4021	            LOCK(data.watchonly_wallet->cs_wallet);
4022	            if (data.watchonly_wallet->IsMine(*wtx->tx) || data.watchonly_wallet->IsFromMe(*wtx->tx)) {
4023	                // Add to watchonly wallet
4024	                const Txid& hash = wtx->GetHash();
4025	                const CWalletTx& to_copy_wtx = *wtx;
4026	                if (!data.watchonly_wallet->LoadToWallet(hash, [&](CWalletTx& ins_wtx, bool new_tx) EXCLUSIVE_LOCKS_REQUIRED(data.watchonly_wallet->cs_wallet) {
4027	                    if (!new_tx) return false;
4028	                    ins_wtx.SetTx(to_copy_wtx.tx);
4029	                    ins_wtx.CopyFrom(to_copy_wtx);
4030	                    return true;
4031	                })) {
4032	                    return util::Error{strprintf(_("Error: Could not add watchonly tx %s to watchonly wallet"), wtx->GetHash().GetHex())};
4033	                }
4034	                watchonly_batch->WriteTx(data.watchonly_wallet->mapWallet.at(hash));
4035	                // Mark as to remove from the migrated wallet only if it does not also belong to it
4036	                if (!is_mine) {
4037	                    txids_to_delete.push_back(hash);
4038	                    continue;
4039	                }
4040	            }
4041	        }
4042	        if (!is_mine) {
4043	            // Both not ours and not in the watchonly wallet
4044	            return util::Error{strprintf(_("Error: Transaction %s in wallet cannot be identified to belong to migrated wallets"), wtx->GetHash().GetHex())};
4045	        }
4046	        // Rewrite the transaction so that anything that may have changed about it in memory also persists to disk
4047	        local_wallet_batch.WriteTx(*wtx);
4048	    }
4049	
4050	    // Do the removes
4051	    if (txids_to_delete.size() > 0) {
4052	        if (auto res = RemoveTxs(local_wallet_batch, txids_to_delete); !res) {
4053	            return util::Error{_("Error: Could not delete watchonly transactions. ") + util::ErrorString(res)};
4054	        }
4055	    }
4056	
4057	    // Pair external wallets with their corresponding db handler
4058	    std::vector<std::pair<std::shared_ptr<CWallet>, std::unique_ptr<WalletBatch>>> wallets_vec;
4059	    if (data.watchonly_wallet) wallets_vec.emplace_back(data.watchonly_wallet, std::move(watchonly_batch));
4060	    if (data.solvable_wallet) wallets_vec.emplace_back(data.solvable_wallet, std::move(solvables_batch));
4061	
4062	    // Write address book entry to disk
4063	    auto func_store_addr = [](WalletBatch& batch, const CTxDestination& dest, const CAddressBookData& entry) {
4064	        auto address{EncodeDestination(dest)};
4065	        if (entry.purpose) batch.WritePurpose(address, PurposeToString(*entry.purpose));
4066	        if (entry.label) batch.WriteName(address, *entry.label);
4067	        for (const auto& [id, request] : entry.receive_requests) {
4068	            batch.WriteAddressReceiveRequest(dest, id, request);
4069	        }
4070	        if (entry.previously_spent) batch.WriteAddressPreviouslySpent(dest, true);
4071	    };
4072	
4073	    // Check the address book data in the same way we did for transactions
4074	    std::vector<CTxDestination> dests_to_delete;
4075	    for (const auto& [dest, record] : m_address_book) {
4076	        // Ensure "receive" entries that are no longer part of the original wallet are transferred to another wallet
4077	        // Entries for everything else ("send") will be cloned to all wallets.
4078	        bool require_transfer = record.purpose == AddressPurpose::RECEIVE && !IsMine(dest);
4079	        bool copied = false;
4080	        for (auto& [wallet, batch] : wallets_vec) {
4081	            LOCK(wallet->cs_wallet);
4082	            if (require_transfer && !wallet->IsMine(dest)) continue;
4083	
4084	            // Copy the entire address book entry
4085	            wallet->m_address_book[dest] = record;
4086	            func_store_addr(*batch, dest, record);
4087	
4088	            copied = true;
4089	            // Only delete 'receive' records that are no longer part of the original wallet
4090	            if (require_transfer) {
4091	                dests_to_delete.push_back(dest);
4092	                break;
4093	            }
4094	        }
4095	
4096	        // Fail immediately if we ever found an entry that was ours and cannot be transferred
4097	        // to any of the created wallets (watch-only, solvable).
4098	        // Means that no inferred descriptor maps to the stored entry. Which mustn't happen.
4099	        if (require_transfer && !copied) {
4100	
4101	            // Skip invalid/non-watched scripts that will not be migrated
4102	            if (not_migrated_dests.contains(dest)) {
4103	                dests_to_delete.push_back(dest);
4104	                continue;
4105	            }
4106	
4107	            return util::Error{_("Error: Address book data in wallet cannot be identified to belong to migrated wallets")};
4108	        }
4109	    }
4110	
4111	    // Persist external wallets address book entries
4112	    for (auto& [wallet, batch] : wallets_vec) {
4113	        if (!batch->TxnCommit()) {
4114	            return util::Error{strprintf(_("Error: Unable to write data to disk for wallet %s"), wallet->GetName())};
4115	        }
4116	    }
4117	
4118	    // Remove the things to delete in this wallet
4119	    if (dests_to_delete.size() > 0) {
4120	        for (const auto& dest : dests_to_delete) {
4121	            if (!DelAddressBookWithDB(local_wallet_batch, dest)) {
4122	                return util::Error{_("Error: Unable to remove watchonly address book data")};
4123	            }
4124	        }
4125	    }
4126	
4127	    // If there was no key material in the main wallet, there should be no records on it anymore.
4128	    // This wallet will be discarded at the end of the process. Only wallets that contain the
4129	    // migrated records will be presented to the user.
4130	    if (!has_spendable_material) {
4131	        if (!m_address_book.empty()) return util::Error{_("Error: Not all address book records were migrated")};
4132	        if (!mapWallet.empty()) return util::Error{_("Error: Not all transaction records were migrated")};
4133	    }
4134	
4135	    return {}; // all good
4136	}
