4151	
4152	bool DoMigration(CWallet& wallet, WalletContext& context, bilingual_str& error, MigrationResult& res) EXCLUSIVE_LOCKS_REQUIRED(wallet.cs_wallet)
4153	{
4154	    AssertLockHeld(wallet.cs_wallet);
4155	
4156	    // Get all of the descriptors from the legacy wallet
4157	    std::optional<MigrationData> data = wallet.GetDescriptorsForLegacy(error);
4158	    if (data == std::nullopt) return false;
4159	
4160	    // Create the watchonly and solvable wallets if necessary
4161	    if (data->watch_descs.size() > 0 || data->solvable_descs.size() > 0) {
4162	        DatabaseOptions options;
4163	        options.require_existing = false;
4164	        options.require_create = true;
4165	        options.require_format = DatabaseFormat::SQLITE;
4166	
4167	        WalletContext empty_context;
4168	        empty_context.args = context.args;
4169	
4170	        // Make the wallets
4171	        options.create_flags = WALLET_FLAG_DISABLE_PRIVATE_KEYS | WALLET_FLAG_BLANK_WALLET | WALLET_FLAG_DESCRIPTORS;
4172	        if (wallet.IsWalletFlagSet(WALLET_FLAG_AVOID_REUSE)) {
4173	            options.create_flags |= WALLET_FLAG_AVOID_REUSE;
4174	        }
4175	        if (wallet.IsWalletFlagSet(WALLET_FLAG_KEY_ORIGIN_METADATA)) {
4176	            options.create_flags |= WALLET_FLAG_KEY_ORIGIN_METADATA;
4177	        }
4178	        if (data->watch_descs.size() > 0) {
4179	            wallet.WalletLogPrintf("Making a new watchonly wallet containing the watched scripts\n");
4180	
4181	            DatabaseStatus status;
4182	            std::vector<bilingual_str> warnings;
4183	            std::string wallet_name = MigrationPrefixName(wallet) + "_watchonly";
4184	            std::unique_ptr<WalletDatabase> database = MakeWalletDatabase(wallet_name, options, status, error);
4185	            if (!database) {
4186	                error = strprintf(_("Wallet file creation failed: %s"), error);
4187	                return false;
4188	            }
4189	
4190	            data->watchonly_wallet = CWallet::CreateNew(empty_context, wallet_name, std::move(database), options.create_flags, /*born_encrypted=*/false, error, warnings);
4191	            if (!data->watchonly_wallet) {
4192	                error = _("Error: Failed to create new watchonly wallet");
4193	                return false;
4194	            }
4195	            res.watchonly_wallet = data->watchonly_wallet;
4196	            LOCK(data->watchonly_wallet->cs_wallet);
4197	
4198	            // Parse the descriptors and add them to the new wallet
4199	            for (const auto& [desc_str, creation_time] : data->watch_descs) {
4200	                // Parse the descriptor
4201	                FlatSigningProvider keys;
4202	                std::string parse_err;
4203	                std::vector<std::unique_ptr<Descriptor>> descs = Parse(desc_str, keys, parse_err, /*require_checksum=*/ true);
4204	                assert(descs.size() == 1); // It shouldn't be possible to have the LegacyScriptPubKeyMan make an invalid descriptor or a multipath descriptors
4205	                assert(!descs.at(0)->IsRange()); // It shouldn't be possible to have LegacyScriptPubKeyMan make a ranged watchonly descriptor
4206	
4207	                // Add to the wallet
4208	                WalletDescriptor w_desc(std::move(descs.at(0)), creation_time, 0, 0, 0);
4209	                if (auto spkm_res = data->watchonly_wallet->AddWalletDescriptor(w_desc, keys, "", false); !spkm_res) {
4210	                    throw std::runtime_error(util::ErrorString(spkm_res).original);
4211	                }
4212	            }
4213	
4214	            // Add the wallet to settings
4215	            UpdateWalletSetting(*context.chain, wallet_name, /*load_on_startup=*/true, warnings);
4216	        }
4217	        if (data->solvable_descs.size() > 0) {
4218	            wallet.WalletLogPrintf("Making a new watchonly wallet containing the unwatched solvable scripts\n");
4219	
4220	            DatabaseStatus status;
4221	            std::vector<bilingual_str> warnings;
4222	            std::string wallet_name = MigrationPrefixName(wallet) + "_solvables";
4223	            std::unique_ptr<WalletDatabase> database = MakeWalletDatabase(wallet_name, options, status, error);
4224	            if (!database) {
4225	                error = strprintf(_("Wallet file creation failed: %s"), error);
4226	                return false;
4227	            }
4228	
4229	            data->solvable_wallet = CWallet::CreateNew(empty_context, wallet_name, std::move(database), options.create_flags, /*born_encrypted=*/false, error, warnings);
4230	            if (!data->solvable_wallet) {
4231	                error = _("Error: Failed to create new watchonly wallet");
4232	                return false;
4233	            }
4234	            res.solvables_wallet = data->solvable_wallet;
4235	            LOCK(data->solvable_wallet->cs_wallet);
4236	
4237	            // Parse the descriptors and add them to the new wallet
4238	            for (const auto& [desc_str, creation_time] : data->solvable_descs) {
4239	                // Parse the descriptor
4240	                FlatSigningProvider keys;
4241	                std::string parse_err;
4242	                std::vector<std::unique_ptr<Descriptor>> descs = Parse(desc_str, keys, parse_err, /*require_checksum=*/ true);
4243	                assert(descs.size() == 1); // It shouldn't be possible to have the LegacyScriptPubKeyMan make an invalid descriptor or a multipath descriptors
4244	                assert(!descs.at(0)->IsRange()); // It shouldn't be possible to have LegacyScriptPubKeyMan make a ranged watchonly descriptor
4245	
4246	                // Add to the wallet
4247	                WalletDescriptor w_desc(std::move(descs.at(0)), creation_time, 0, 0, 0);
4248	                if (auto spkm_res = data->solvable_wallet->AddWalletDescriptor(w_desc, keys, "", false); !spkm_res) {
4249	                    throw std::runtime_error(util::ErrorString(spkm_res).original);
4250	                }
4251	            }
4252	
4253	            // Add the wallet to settings
4254	            UpdateWalletSetting(*context.chain, wallet_name, /*load_on_startup=*/true, warnings);
4255	        }
4256	    }
4257	
4258	    // Add the descriptors to wallet, remove LegacyScriptPubKeyMan, and cleanup txs and address book data
4259	    return RunWithinTxn(wallet.GetDatabase(), /*process_desc=*/"apply migration process", [&](WalletBatch& batch) EXCLUSIVE_LOCKS_REQUIRED(wallet.cs_wallet){
4260	        if (auto res_migration = wallet.ApplyMigrationData(batch, *data); !res_migration) {
4261	            error = util::ErrorString(res_migration);
4262	            return false;
4263	        }
4264	        wallet.WalletLogPrintf("Wallet migration complete.\n");
4265	        return true;
4266	    });
4267	}
