4269	util::Result<MigrationResult> MigrateLegacyToDescriptor(const std::string& wallet_name, const SecureString& passphrase, WalletContext& context)
4270	{
4271	    std::vector<bilingual_str> warnings;
4272	    bilingual_str error;
4273	
4274	    // The only kind of wallets that could be loaded are descriptor ones, which don't need to be migrated.
4275	    if (auto wallet = GetWallet(context, wallet_name)) {
4276	        assert(wallet->IsWalletFlagSet(WALLET_FLAG_DESCRIPTORS));
4277	        return util::Error{_("Error: This wallet is already a descriptor wallet")};
4278	    } else {
4279	        // Check if the wallet is BDB
4280	        const auto& wallet_path = GetWalletPath(wallet_name);
4281	        if (!wallet_path) {
4282	            return util::Error{util::ErrorString(wallet_path)};
4283	        }
4284	        if (!fs::exists(*wallet_path)) {
4285	            return util::Error{_("Error: Wallet does not exist")};
4286	        }
4287	        if (!IsBDBFile(BDBDataFile(*wallet_path))) {
4288	            return util::Error{_("Error: This wallet is already a descriptor wallet")};
4289	        }
4290	    }
4291	
4292	    // Load the wallet but only in the context of this function.
4293	    // No signals should be connected nor should anything else be aware of this wallet
4294	    WalletContext empty_context;
4295	    empty_context.args = context.args;
4296	    DatabaseOptions options;
4297	    options.require_existing = true;
4298	    options.require_format = DatabaseFormat::BERKELEY_RO;
4299	    DatabaseStatus status;
4300	    std::unique_ptr<WalletDatabase> database = MakeWalletDatabase(wallet_name, options, status, error);
4301	    if (!database) {
4302	        return util::Error{Untranslated("Wallet file verification failed.") + Untranslated(" ") + error};
4303	    }
4304	
4305	    // Make the local wallet
4306	    std::shared_ptr<CWallet> local_wallet = CWallet::LoadExisting(empty_context, wallet_name, std::move(database), error, warnings);
4307	    if (!local_wallet) {
4308	        return util::Error{Untranslated("Wallet loading failed.") + Untranslated(" ") + error};
4309	    }
4310	
4311	    return MigrateLegacyToDescriptor(std::move(local_wallet), passphrase, context);
4312	}
4313	
4314	util::Result<MigrationResult> MigrateLegacyToDescriptor(std::shared_ptr<CWallet> local_wallet, const SecureString& passphrase, WalletContext& context)
4315	{
4316	    MigrationResult res;
4317	    bilingual_str error;
4318	    std::vector<bilingual_str> warnings;
4319	
4320	    DatabaseOptions options;
4321	    options.require_existing = true;
4322	    DatabaseStatus status;
4323	
4324	    const std::string wallet_name = local_wallet->GetName();
4325	
4326	    // Before anything else, check if there is something to migrate.
4327	    if (local_wallet->IsWalletFlagSet(WALLET_FLAG_DESCRIPTORS)) {
4328	        return util::Error{_("Error: This wallet is already a descriptor wallet")};
4329	    }
4330	
4331	    // Make a backup of the DB in the wallet's directory with a unique filename
4332	    // using the wallet name and current timestamp. The backup filename is based
4333	    // on the name of the parent directory containing the wallet data in most
4334	    // cases, but in the case where the wallet name is a path to a data file,
4335	    // the name of the data file is used, and in the case where the wallet name
4336	    // is blank, "default_wallet" is used.
4337	    const std::string backup_prefix = wallet_name.empty() ? MigrationPrefixName(*local_wallet) : [&] {
4338	        // fs::weakly_canonical resolves relative specifiers and remove trailing slashes.
4339	        const auto legacy_wallet_path = fs::weakly_canonical(GetWalletDir() / fs::PathFromString(wallet_name));
4340	        return fs::PathToString(legacy_wallet_path.filename());
4341	    }();
4342	
4343	    fs::path backup_filename = fs::PathFromString(strprintf("%s_%d.legacy.bak", backup_prefix, GetTime()));
4344	    fs::path backup_path = fsbridge::AbsPathJoin(GetWalletDir(), backup_filename);
4345	    if (!local_wallet->BackupWallet(fs::PathToString(backup_path))) {
4346	        return util::Error{_("Error: Unable to make a backup of your wallet")};
4347	    }
4348	    res.backup_path = backup_path;
4349	
4350	    bool success = false;
4351	
4352	    // Unlock the wallet if needed
4353	    if (local_wallet->IsLocked() && !local_wallet->Unlock(passphrase)) {
4354	        if (passphrase.find('\0') == std::string::npos) {
4355	            return util::Error{Untranslated("Error: Wallet decryption failed, the wallet passphrase was not provided or was incorrect.")};
4356	        } else {
4357	            return util::Error{Untranslated("Error: Wallet decryption failed, the wallet passphrase entered was incorrect. "
4358	                                            "The passphrase contains a null character (ie - a zero byte). "
4359	                                            "If this passphrase was set with a version of this software prior to 25.0, "
4360	                                            "please try again with only the characters up to — but not including — "
4361	                                            "the first null character.")};
4362	        }
4363	    }
4364	
4365	    // Indicates whether the current wallet is empty after migration.
4366	    // Notes:
4367	    // When non-empty: the local wallet becomes the main spendable wallet.
4368	    // When empty: The local wallet is excluded from the result, as the
4369	    //             user does not expect an empty spendable wallet after
4370	    //             migrating only watch-only scripts.
4371	    bool empty_local_wallet = false;
4372	
4373	    {
4374	        LOCK(local_wallet->cs_wallet);
4375	        // First change to using SQLite
4376	        if (!local_wallet->MigrateToSQLite(error)) return util::Error{error};
4377	
4378	        // Do the migration of keys and scripts for non-empty wallets, and cleanup if it fails
4379	        if (HasLegacyRecords(*local_wallet)) {
4380	            success = DoMigration(*local_wallet, context, error, res);
4381	            // No scripts mean empty wallet after migration
4382	            empty_local_wallet = local_wallet->GetAllScriptPubKeyMans().empty();
4383	        } else {
4384	            // Make sure that descriptors flag is actually set
4385	            local_wallet->SetWalletFlag(WALLET_FLAG_DESCRIPTORS);
4386	            success = true;
4387	        }
4388	    }
4389	
4390	    // In case of loading failure, we need to remember the wallet files we have created to remove.
4391	    // A `set` is used as it may be populated with the same wallet directory paths multiple times,
4392	    // both before and after loading. This ensures the set is complete even if one of the wallets
4393	    // fails to load.
4394	    std::set<fs::path> wallet_files_to_remove;
4395	    std::set<fs::path> wallet_empty_dirs_to_remove;
4396	
4397	    // Helper to track wallet files and directories for cleanup on failure.
4398	    // Only directories of wallets created during migration (not the main wallet) are tracked.
4399	    auto track_for_cleanup = [&](const CWallet& wallet) {
4400	        const auto files = wallet.GetDatabase().Files();
4401	        wallet_files_to_remove.insert(files.begin(), files.end());
4402	        if (wallet.GetName() != wallet_name) {
4403	            // If this isn’t the main wallet, mark its directory for removal.
4404	            // This applies to the watch-only and solvable wallets.
4405	            // Wallets stored directly as files in the top-level directory
4406	            // (e.g. default unnamed wallets) don’t have a removable parent directory.
4407	            wallet_empty_dirs_to_remove.insert(fs::PathFromString(wallet.GetDatabase().Filename()).parent_path());
4408	        }
4409	    };
4410	
4411	
4412	    if (success) {
4413	        Assume(!res.wallet); // We will set it here.
4414	        // Check if the local wallet is empty after migration
4415	        if (empty_local_wallet) {
4416	            // This wallet has no records. We can safely remove it.
4417	            std::vector<fs::path> paths_to_remove = local_wallet->GetDatabase().Files();
4418	            local_wallet.reset();
4419	            for (const auto& path_to_remove : paths_to_remove) fs::remove(path_to_remove);
4420	        }
4421	
4422	        LogInfo("Loading new wallets after migration...\n");
4423	        // Migration successful, load all the migrated wallets.
4424	        for (std::shared_ptr<CWallet>* wallet_ptr : {&local_wallet, &res.watchonly_wallet, &res.solvables_wallet}) {
4425	            if (success && *wallet_ptr) {
4426	                std::shared_ptr<CWallet>& wallet = *wallet_ptr;
4427	                // Track db path and load wallet
4428	                track_for_cleanup(*wallet);
4429	                assert(wallet.use_count() == 1);
4430	                std::string wallet_name = wallet->GetName();
4431	                wallet.reset();
4432	                wallet = LoadWallet(context, wallet_name, /*load_on_start=*/std::nullopt, options, status, error, warnings);
4433	                if (!wallet) {
4434	                    LogError("Failed to load wallet '%s' after migration. Rolling back migration to preserve consistency. "
4435	                             "Error cause: %s\n", wallet_name, error.original);
4436	                    success = false;
4437	                    break;
4438	                }
4439	
4440	                // Set the first successfully loaded wallet as the main one.
4441	                // The loop order is intentional and must always start with the local wallet.
4442	                if (!res.wallet) {
4443	                    res.wallet_name = wallet->GetName();
4444	                    res.wallet = std::move(wallet);
4445	                }
4446	            }
4447	        }
4448	    }
4449	    if (!success) {
4450	        // Make list of wallets to cleanup
4451	        std::vector<std::shared_ptr<CWallet>> created_wallets;
4452	        if (local_wallet) created_wallets.push_back(std::move(local_wallet));
4453	        if (res.watchonly_wallet) created_wallets.push_back(std::move(res.watchonly_wallet));
4454	        if (res.solvables_wallet) created_wallets.push_back(std::move(res.solvables_wallet));
4455	
4456	        // Get the directories to remove after unloading
4457	        for (std::shared_ptr<CWallet>& wallet : created_wallets) {
4458	            track_for_cleanup(*wallet);
4459	        }
4460	
4461	        // Unload the wallets
4462	        for (std::shared_ptr<CWallet>& w : created_wallets) {
4463	            if (w->HaveChain()) {
4464	                // Unloading for wallets that were loaded for normal use
4465	                if (!RemoveWallet(context, w, /*load_on_start=*/false)) {
4466	                    error += _("\nUnable to cleanup failed migration");
4467	                    return util::Error{error};
4468	                }
4469	                WaitForDeleteWallet(std::move(w));
4470	            } else {
4471	                // Unloading for wallets in local context
4472	                assert(w.use_count() == 1);
4473	                w.reset();
4474	            }
4475	        }
4476	
4477	        // First, delete the db files we have created throughout this process and nothing else
4478	        for (const fs::path& file : wallet_files_to_remove) {
4479	            fs::remove(file);
4480	        }
4481	
4482	        // Second, delete the created wallet directories and nothing else. They must be empty at this point.
4483	        for (const fs::path& dir : wallet_empty_dirs_to_remove) {
4484	            Assume(fs::is_empty(dir));
4485	            fs::remove(dir);
4486	        }
4487	
4488	        // Restore the backup
4489	        // Convert the backup file to the wallet db file by renaming it and moving it into the wallet's directory.
4490	        bilingual_str restore_error;
4491	        const auto& ptr_wallet = RestoreWallet(context, backup_path, wallet_name, /*load_on_start=*/std::nullopt, status, restore_error, warnings, /*load_after_restore=*/false, /*allow_unnamed=*/true);
4492	        if (!restore_error.empty()) {
4493	            error += restore_error + _("\nUnable to restore backup of wallet.");
4494	            return util::Error{error};
4495	        }
4496	        // Verify that the legacy wallet is not loaded after restoring from the backup.
4497	        assert(!ptr_wallet);
4498	
4499	        return util::Error{error};
4500	    }
4501	    return res;
4502	}
