271	inline CAmount CalculateOutputValue(const TxType& tx)
272	{
273	    return std::accumulate(tx.vout.cbegin(), tx.vout.cend(), CAmount{0}, [](CAmount sum, const auto& txout) { return sum + txout.nValue; });
274	}
