445	    assert(ret == success);
446	    DataStream ssin;
447	    ssin << TX_WITH_WITNESS(inputm);
448	    ssin >> TX_WITH_WITNESS(input);
449	    assert(input.vin.size() == 1);
450	    assert(input.vin[0] == inputm.vin[0]);
