939	    g_bare_multi = true;
940	    t.vout[0].scriptPubKey = GetScriptForMultisig(1, {key.GetPubKey()}); // simple 1-of-1
941	    t.vin.resize(1);
942	    t.vin[0].scriptSig = CScript() << std::vector<unsigned char>(65, 0);
