1287	    tx_spend.vin[0].scriptSig = CScript{} << ToByteVector(redeem_script);
1288	    AddCoins(coins, CTransaction{tx_create}, 0, false);
1289	    BOOST_CHECK(::SpendsNonAnchorWitnessProg(CTransaction{tx_spend}, coins));
1290	    tx_spend.vin[0].scriptSig.clear();
1291	
1292	    // Undefined version 1 witness program
1293	    tx_create.vout[0].scriptPubKey = GetScriptForDestination(WitnessUnknown{1, {0x42, 0x42}});
1294	    BOOST_CHECK_EQUAL(Solver(tx_create.vout[0].scriptPubKey, sol_dummy), TxoutType::WITNESS_UNKNOWN);
1295	    tx_spend.vin[0].prevout.hash = tx_create.GetHash();
1296	    AddCoins(coins, CTransaction{tx_create}, 0, false);
1297	    BOOST_CHECK(::SpendsNonAnchorWitnessProg(CTransaction{tx_spend}, coins));
1298	
1299	    // P2SH-wrapped undefined version 1 witness program
1300	    redeem_script = tx_create.vout[0].scriptPubKey;
1301	    tx_create.vout[0].scriptPubKey = GetScriptForDestination(ScriptHash(redeem_script));
1302	    BOOST_CHECK_EQUAL(Solver(tx_create.vout[0].scriptPubKey, sol_dummy), TxoutType::SCRIPTHASH);
