1305	    AddCoins(coins, CTransaction{tx_create}, 0, false);
1306	    BOOST_CHECK(::SpendsNonAnchorWitnessProg(CTransaction{tx_spend}, coins));
1307	    tx_spend.vin[0].scriptSig.clear();
1308	    BOOST_CHECK(!::SpendsNonAnchorWitnessProg(CTransaction{tx_spend}, coins));
1309	
1310	    // Various undefined version >1 32-byte witness programs.
1311	    const auto program{ToByteVector(XOnlyPubKey{pubkey})};
1312	    for (int i{2}; i <= 16; ++i) {
1313	        tx_create.vout[0].scriptPubKey = GetScriptForDestination(WitnessUnknown{i, program});
