63	    // scriptSig:    <sig> <sig...> <serialized_script>
64	    // scriptPubKey: HASH160 <hash> EQUAL
65	
66	    // Test SignSignature() (and therefore the version of Solver() that signs transactions)
67	    FillableSigningProvider keystore;
