221	static unsigned int GetLen(unsigned char chHeader)
222	{
223	    if (chHeader == 2 || chHeader == 3)
224	        return CPubKey::COMPRESSED_SIZE;
225	    if (chHeader == 4 || chHeader == 6 || chHeader == 7)
226	        return CPubKey::SIZE;
227	    return 0;
228	}
